import { Link, useNavigate, useLocation } from "react-router-dom";
import { useState } from "react";
import {
  Menu,
  X,
  Search,
  Home,
  FileText,
  CheckCircle,
  Shield,
  Info
} from "lucide-react";

export default function Navbar() {

  const navigate = useNavigate();
  const location = useLocation();
  const pathname = location.pathname || "/";

  const accessToken = localStorage.getItem("accessToken");
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  const isLoggedIn = Boolean(accessToken);
  const isAdmin = user?.role === "admin";

  const [open, setOpen] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [search, setSearch] = useState("");

  const logout = () => {

    localStorage.removeItem("accessToken");
    localStorage.removeItem("refreshToken");
    localStorage.removeItem("user");

    navigate("/login", { replace: true });

  };

  const handleSearch = (e) => {

    e.preventDefault();

    if (!search.trim()) return;

    navigate(`/dashboard?search=${search}`);

    setSearch("");

  };

  return (

    <nav className="bg-white border-b sticky top-0 z-50">

      <div className="max-w-7xl mx-auto px-6 py-3 flex items-center justify-between">

        {/* LOGO */}

        <Link
          to={isLoggedIn ? "/dashboard" : "/login"}
          className="text-xl font-extrabold tracking-wide"
        >
          <span className="text-blue-600">we</span>
          <span className="text-gray-900">FOUND</span>
          <span className="text-green-600">it</span>
        </Link>


        {/* SEARCH */}

        {isLoggedIn && (

          <form
            onSubmit={handleSearch}
            className="hidden md:flex items-center bg-gray-100 rounded-lg px-3 py-1.5 w-72"
          >

            <Search size={16} className="text-gray-500 mr-2" />

            <input
              type="text"
              placeholder="Search items..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="bg-transparent outline-none text-sm w-full"
            />

          </form>

        )}


        {/* RIGHT MENU */}

        <div className="hidden md:flex items-center gap-4">

          {isLoggedIn && (

            <>
              <IconLink
                to="/dashboard"
                active={pathname === "/dashboard"}
                icon={<Home size={18} />}
              />

              <IconLink
                to="/my-posts"
                active={pathname === "/my-posts"}
                icon={<FileText size={18} />}
              />

              <IconLink
                to="/returned"
                active={pathname === "/returned"}
                icon={<CheckCircle size={18} />}
              />

              {isAdmin && (
                <IconLink
                  to="/admin"
                  active={pathname === "/admin"}
                  icon={<Shield size={18} />}
                />
              )}

            </>

          )}

          {/* USER DROPDOWN */}

          {isLoggedIn && (

            <div className="relative">

              <button
                onClick={() => setMenuOpen(!menuOpen)}
                className="flex items-center gap-2 text-sm font-medium text-gray-700"
              >
                {user?.name}
              </button>

              {menuOpen && (

                <div className="absolute right-0 mt-2 w-40 bg-white border rounded-lg shadow-lg">

                  <Link
                    to="/about"
                    className="flex items-center gap-2 px-4 py-2 hover:bg-gray-100"
                    onClick={() => setMenuOpen(false)}
                  >
                    <Info size={16} />
                    About
                  </Link>

                  <button
                    onClick={logout}
                    className="w-full text-left px-4 py-2 text-red-600 hover:bg-red-50"
                  >
                    Logout
                  </button>

                </div>

              )}

            </div>

          )}

        </div>


        {/* MOBILE BUTTON */}

        <button
          onClick={() => setOpen(!open)}
          className="md:hidden"
        >
          {open ? <X size={24} /> : <Menu size={24} />}
        </button>

      </div>


      {/* MOBILE MENU */}

      {open && (

        <div className="md:hidden border-t">

          <MobileLink to="/dashboard" setOpen={setOpen}>
            Dashboard
          </MobileLink>

          <MobileLink to="/my-posts" setOpen={setOpen}>
            My Posts
          </MobileLink>

          <MobileLink to="/returned" setOpen={setOpen}>
            Returned
          </MobileLink>

          {isAdmin && (
            <MobileLink to="/admin" setOpen={setOpen}>
              Admin
            </MobileLink>
          )}

          <MobileLink to="/about" setOpen={setOpen}>
            About
          </MobileLink>

          <button
            onClick={logout}
            className="block w-full text-left px-5 py-3 text-red-600 hover:bg-red-50"
          >
            Logout
          </button>

        </div>

      )}

    </nav>

  );

}


/* ICON NAV */

function IconLink({ to, icon, active }) {

  return (

    <Link
      to={to}
      className={`p-2 rounded-lg transition
      ${active
        ? "bg-blue-50 text-blue-600"
        : "text-gray-600 hover:bg-gray-100"}`}
    >

      {icon}

    </Link>

  );

}


/* MOBILE LINK */

function MobileLink({ to, children, setOpen }) {

  return (

    <Link
      to={to}
      onClick={() => setOpen(false)}
      className="block px-5 py-3 text-gray-700 hover:bg-gray-100"
    >

      {children}

    </Link>

  );

}
